import os
for root, dirs, files in os.walk('/workspace'):
    # prune deep
    depth = root[len('/workspace'):].count('/')
    if depth > 3:
        dirs[:] = []
        continue
    for f in files:
        if f.endswith('.md'):
            print(os.path.join(root, f))

base = '/workspace/5a74a0c8-727d-4d16-ae2e-88cda2fa305c'
for f in sorted(os.listdir(base)):
    if f.endswith('.md'):
        p = os.path.join(base, f)
        print(f, os.path.getsize(p))
